def main():
    if len(sys.argv) != 2:
        raise SystemExit("usage: import_review_design.py <design.md>")
    p = Path(sys.argv[1])
    md = p.read_text(encoding="utf-8")
    for topic_id in META:
        build(md, topic_id)

if __name__ == "__main__":
    main()
